const bcrypt = require('bcrypt');
const saltRounds = 10;

async function hashPassword(plainText) {
  return await bcrypt.hash(plainText, saltRounds);
}

async function verifyPassword(plainText, hash) {
  return await bcrypt.compare(plainText, hash);
}

async function main() {
  const password = 'mySecret123';
  const hash1 = await hashPassword(password);
  const hash2 = await hashPassword(password);
  console.log('Hash1:', hash1);
  console.log('Hash2:', hash2);
  console.log('Same password?', hash1 === hash2); // false

  const correct = await verifyPassword(password, hash1);
  console.log('Correct password matches hash1:', correct); // true

  const wrong = await verifyPassword('wrong', hash1);
  console.log('Wrong password matches hash1:', wrong); // false
}

main().catch(console.error);
